{"meta": null, "content": [{"type": "text", "text": "{"content":"10437: \n10438: bool PresShell::DoReflow(nsIFrame* target, bool aInterruptible,\n10439:                          OverflowChangedTracker* aOverflowTracker) {\n10440:   nsIURI* uri = mDocument-\u003eGetDocumentURI();\n10441:   AUTO_PROFILER_LABEL_DYNAMIC_NSCSTRING_RELEVANT_FOR_JS(\n10442:       \"Reflow\", LAYOUT_Reflow, uri ? uri-\u003eGetSpecOrDefault() : \"N/A\"_ns);\n10443: \n10444:   PerfStats::AutoMetricRecording\u003cPerfStats::Metric::Reflowing\u003e autoRecording;\n10445: \n10446:   gfxTextPerfMetrics* tp = mPresContext-\u003eGetTextPerfMetrics();\n10447:   TimeStamp timeStart;\n10448:   if (tp) {\n10449:     tp-\u003eAccumulate();\n10450:     tp-\u003ereflowCount++;\n10451:     timeStart = TimeStamp::Now();\n10452:   }\n10453: \n10454:   // set up a cache that saves all nodes contained in each selection,\n10455:   // allowing a fast lookup in `nsTextFrame::IsFrameSelected()`.\n10456:   // This cache only lives throughout this reflow call.\n10457:   SelectionNodeCache cache(*this);\n10458: \n10459:   // Schedule a paint, but don't actually mark this frame as changed for\n10460:   // retained DL building purposes. If any child frames get moved, then\n10461:   // they will schedule paint again. We could probaby skip this, and just\n10462:   // schedule a similar paint when a frame is deleted.\n10463:   target-\u003eSchedulePaint(nsIFrame::PAINT_DEFAULT, false);\n10464: \n10465:   Maybe\u003cuint64_t\u003e innerWindowID;\n10466:   if (auto* window = mDocument-\u003eGetInnerWindow()) {\n10467:     innerWindowID = Some(window-\u003eWindowID());\n10468:   }\n10469:   AutoProfilerTracing tracingLayoutFlush(\n10470:       aInterruptible ? \"Reflow (interruptible)\" : \"Reflow (sync)\",\n10471:       geckoprofiler::category::LAYOUT, std::move(mReflowCause), innerWindowID);\n10472:   mReflowCause = nullptr;\n10473: \n10474:   FlushPendingScrollAnchorSelections();\n10475: \n10476:   const bool isRoot = tar