2348: void nsDisplayList::PaintRoot(nsDisplayListBuilder* aBuilder, gfxContext* aCtx,
2349:                               uint32_t aFlags,
2350:                               Maybe<double> aDisplayListBuildTime) {
2351:   AUTO_PROFILER_LABEL("nsDisplayList::PaintRoot", GRAPHICS);
2352: 
2353:   RefPtr<WebRenderLayerManager> layerManager;
2354:   WindowRenderer* renderer = nullptr;
2355:   bool widgetTransaction = false;
2356:   bool doBeginTransaction = true;
2357:   if (aFlags & PAINT_USE_WIDGET_LAYERS) {
2358:     renderer = aBuilder->GetWidgetWindowRenderer();
2359:     if (renderer) {
2360:       // The fallback renderer doesn't retain any content, so it's
2361:       // not meaningful to use it when drawing to an external context.
2362:       if (aCtx && renderer->AsFallback()) {
