2367:         doBeginTransaction = !(aFlags & PAINT_EXISTING_TRANSACTION);
2368:         widgetTransaction = true;
2369:       }
2370:     }
2371:   }
2372: 
2373:   nsIFrame* frame = aBuilder->RootReferenceFrame();
