2385:     // EndTransaction.
2386:     if (widgetTransaction ||
2387:         // SVG-as-an-image docs don't paint as part of the retained layer tree,
2388:         // but they still need the invalidation state bits cleared in order for
2389:         // invalidation for CSS/SMIL animation to work properly.
2390:         (document && document->IsBeingUsedAsImage())) {
2391:       DL_LOGD("Clearing invalidation state bits");
2392:       frame->ClearInvalidationStateBits();
2393:     }
2394:   });
