2400:     }
2401:     Paint(aBuilder, aCtx, presContext->AppUnitsPerDevPixel());
2402: 
2403:     return;
2404:   }
2405: 
2406:   if (renderer->GetBackendType() == LayersBackend::LAYERS_WR) {
2407:     MOZ_ASSERT(layerManager);
2408:     if (doBeginTransaction) {
2409:       if (aCtx) {
2410:         if (!layerManager->BeginTransactionWithTarget(aCtx, nsCString())) {
