2412:         }
2413:       } else {
2414:         if (!layerManager->BeginTransaction(nsCString())) {
2415:           return;
2416:         }
2417:       }
2418:     }
2419: 
2420:     layerManager->SetTransactionIdAllocator(presContext->RefreshDriver());
