2428:     if (!sent) {
2429:       auto* wrManager = static_cast<WebRenderLayerManager*>(layerManager.get());
2430: 
2431:       nsIDocShell* docShell = presContext->GetDocShell();
2432:       WrFiltersHolder wrFilters;
2433:       gfx::Matrix5x4* colorMatrix =
2434:           nsDocShell::Cast(docShell)->GetColorMatrix();
2435:       if (colorMatrix) {
2436:         // Note: This color matrix was added here in for accessibility in
2437:         // https://bugzilla.mozilla.org/show_bug.cgi?id=1431466 , it could be
2438:         // done with regular SVG in the document as long as it is accelerated,
2439:         // and it's probably best to do this in linearRGB, now that it is
2440:         // feasible to do so
2441:         // TODO(ahale): Make sure to test this works correctly before enabling
2442:         if (StaticPrefs::gfx_webrender_svg_filter_effects() &&
2443:             StaticPrefs::
2444:                 gfx_webrender_svg_filter_effects_also_use_for_docshell_fecolormatrix()) {
