2450:           node.input.buffer_id = wr::FilterOpGraphPictureBufferId::None();
2451:           node.input2.buffer_id = wr::FilterOpGraphPictureBufferId::None();
2452:           node.subregion = subregion;
2453:           wrFilters.filters.AppendElement(
