  "stages": [
    {
      "stage": 1,
      "name": "Style Change Notification",
      "description": "A CSS property change on a DOM element is recorded as a restyle hint. The element is marked dirty in the Servo style system so it will be re-traversed on the next flush.",
      "primary_files": [
        "layout/style/RestyleManager.cpp",
        "layout/base/nsPresContext.cpp"
      ],
      "key_functions": [
        {
          "function": "RestyleManager::PostRestyleEvent(Element*, RestyleHint, nsChangeHint)",
          "file": "layout/style/RestyleManager.cpp",
          "line": 2383,
          "role": "Main entry point for posting a restyle. Calls Servo_NoteExplicitHints() to mark the element dirty in the Servo style tree. Called from PresShell::ElementStateChanged(), AttributeChanged(), CharacterDataChanged(), etc."
        },
        {
          "function": "RestyleManager::RebuildAllStyleData(nsChangeHint, RestyleHint)",
          "file": "layout/style/RestyleManager.cpp",
          "line": 2442,
          "role": "Global restyle: iterates all document style roots and calls PostRestyleEvent() on each. Triggered by nsPresContext::PostRebuildAllStyleDataEvent() for viewport/media-query changes."
        },
        {
          "function": "nsPresContext::PostRebuildAllStyleDataEvent(nsChangeHint, RestyleHint)",
          "file": "layout/base/nsPresContext.cpp",
          "line": 1987,
          "role": "Schedules a full style rebuild (e.g. after a stylesheet change or viewport resize). Delegates to RestyleManager::RebuildAllStyleData()."
        },
        {
          "function": "Servo_NoteExplicitHints(Element*, RestyleHint, nsChangeHint)",
          "file": "layout/style/RestyleManager.cpp",
          "line": 2422,
          "role": "FFI call into Rust/Servo that marks the element with dirty bits (ELEMENT_HAS_DIRTY_DESCENDANTS_FOR_SERVO) and sets the document's servo restyle root."
        }
      ]
    },
    {
      "stage": 2,
      "name": "Style Flush & Servo Traversal",
      "description": "On the next refresh-driver tick (or explicit flush), PresShell drives a style flush. The Servo parallel style traversal recomputes computed styles for all dirty elements, then a post-traversal updates frame ComputedStyle objects and collects nsChangeHint entries.",
      "primary_files": [
        "layout/base/PresShell.cpp",
        "layout/style/RestyleManager.cpp",
        "layout/style/ServoStyleSet.cpp"
      ],
      "key_functions": [
        {
          "function": "PresShell::DoFlushPendingNotifications(ChangesToFlush)",
          "file": "layout/base/PresShell.cpp",
          "line": 4357,
          "role": "Central flush dispatcher. Calls StyleSet()->UpdateStylistIfNeeded(), then mPresContext->RestyleManager()->ProcessPendingRestyles() (line 4487), then DoFlushLayout() (line 4497)."
        },
        {
          "function": "RestyleManager::ProcessPendingRestyles()",
          "file": "layout/style/RestyleManager.cpp",
          "line": 3284,
          "role": "Public entry point for style flushing. Calls DoProcessPendingRestyles(ServoTraversalFlags::Empty)."
        },
        {
          "function": "RestyleManager::DoProcessPendingRestyles(ServoTraversalFlags)",
          "file": "layout/style/RestyleManager.cpp",
          "line": 3087,
          "role": "Core restyle loop. Calls styleSet->StyleDocument(aFlags) in a loop (line 3145). After each traversal, calls ProcessPostTraversal() for each dirty root (line 3174) to update frame styles and collect change hints, then calls ProcessRestyledFrames() (line 3193) to act on those hints."
        },
        {
          "function": "ServoStyleSet::StyleDocument(ServoTraversalFlags)",
          "file": "layout/style/ServoStyleSet.cpp",
          "line": 809,
          "role": "Drives the Servo parallel style traversal. Calls Servo_TraverseSubtree(root, mRawData.get(), &snapshots, aFlags) (line 846) — the Rust FFI call that recomputes computed styles for all dirty elements in the subtree, potentially in parallel."
        }
      ]
    },
    {
      "stage": 3,
      "name": "Frame Style Recomputation & Change Hint Processing",
      "description": "After the Servo traversal, a post-traversal walk updates each frame's ComputedStyle pointer and computes nsChangeHint values describing what layout/paint work is needed. ProcessRestyledFrames() then acts on those hints.",
      "primary_files": [
        "layout/style/RestyleManager.cpp",
        "layout/style/nsChangeHint.h",
        "layout/style/nsStyleChangeList.cpp"
      ],
      "key_functions": [
        {
          "function": "RestyleManager::ProcessPostTraversal(Element*, ServoRestyleState&, ServoPostTraversalFlags)",
          "file": "layout/style/RestyleManager.cpp",
          "line": 3174,
          "role": "Called for each dirty root after Servo_TraverseSubtree. Walks the frame tree, calls nsIFrame::UpdateStyle() / DidSetComputedStyle() to install new ComputedStyle objects, and appends nsChangeHint entries to nsStyleChangeList."
